dslRule:
/*!id: collections.modernize.hashtable-to-map-generic*/
/*!description: Widens Hashtable type reference to Map interface (e.g., in declarations, casts).*/
/*!severity: info*/
java.util.Hashtable<$K, $V>
=> java.util.Map<$K, $V>
;;

/*!id: collections.modernize.hashtable-to-map-raw*/
/*!description: Widens raw Hashtable type reference to Map interface (e.g., in declarations, casts).*/
/*!severity: info*/
java.util.Hashtable
=> java.util.Map
;;

/*!id: collections.modernize.new-hashtable-to-hashmap-noarg*/
/*!description: Replaces new Hashtable() with new HashMap() for local variables (performance/modernization). Guarded to preserve thread-safety semantics for non-local variables.*/
/*!severity: info*/
new java.util.Hashtable() :: isAssignedToLocalVariable()
=> new java.util.HashMap()
;;

/*!id: collections.modernize.new-hashtable-to-hashmap-capacity*/
/*!description: Replaces new Hashtable(int capacity) with new HashMap(int capacity) for local variables (performance/modernization). Guarded to preserve thread-safety semantics for non-local variables.*/
/*!severity: info*/
new java.util.Hashtable($capacity) :: isAssignedToLocalVariable()
=> new java.util.HashMap($capacity)
;;

/*!id: collections.modernize.new-hashtable-to-hashmap-collection*/
/*!description: Replaces new Hashtable(Collection c) with new HashMap(Collection c) for local variables (performance/modernization). Guarded to preserve thread-safety semantics for non-local variables.*/
/*!severity: info*/
new java.util.Hashtable($collection) :: isAssignedToLocalVariable()
=> new java.util.HashMap($collection)
;;

